    {
        static void Main(string[] args)
        {
            string MyName, MyEyes, MyTeeth, MyHair;
            int MyAge, MyHeight, MyWeight;

            MyName = "Zed A. Shaw";
            MyAge = 35;
            MyHeight = 74;  // inches
            MyWeight = 180; // lbs
            MyEyes = "Blue";
